 1	import * as React from 'react';
 2	
 3	import { WizardDescriptionItem } from '@catalog/wizard/components/WizardDescriptionItem';
 4	import { V1Interface, V1Network } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { BRIDGE, MASQUERADE, SRIOV } from '@kubevirt-utils/resources/vm/utils/constants';
 7	import { getNetworkInterfaceRowData } from '@kubevirt-utils/resources/vm/utils/network/rowData';
 8	import { getPrintableNetworkInterfaceType } from '@kubevirt-utils/resources/vm/utils/network/selectors';
 9	import { DescriptionList, Stack, StackItem } from '@patternfly/react-core';
10	
11	export const interfacesTypes = {
12	  [BRIDGE]: 'Bridge',
13	  [MASQUERADE]: 'Masquerade',
14	  [SRIOV]: 'SR-IOV',
15	};
16	
17	export const WizardOverviewNetworksTable: React.FC<{
18	  interfaces: V1Interface[];
19	  isInlineGrid?: boolean;
20	  networks: V1Network[];
21	}> = React.memo(({ interfaces = [], isInlineGrid, networks = [] }) => {
22	  const { t } = useKubevirtTranslation();
23	  const networkData = getNetworkInterfaceRowData(networks, interfaces);
24	
25	  return (
26	    <DescriptionList
27	      className="pf-v6-c-description-list"
28	      columnModifier={{ default: '3Col' }}
29	      isInlineGrid={isInlineGrid}
30	    >
31	      <WizardDescriptionItem
32	        description={
33	          <Stack>
34	            {networkData.map((n) => (
35	              <StackItem key={n.network.name}>{n.network.name}</StackItem>
36	            ))}
37	          </Stack>
38	        }
39	        title={t('Name')}
40	      />
41	      <WizardDescriptionItem
42	        description={
43	          <Stack>
44	            {networkData.map((n) => (
45	              <StackItem key={n.network.name}>
46	                {n.network.pod ? t('Pod networking') : n.network.multus?.networkName || '-'}
47	              </StackItem>
48	            ))}
49	          </Stack>
50	        }
51	        title={t('Network')}
52	      />
53	      <WizardDescriptionItem
54	        description={
55	          <Stack>
56	            {networkData.map((n) => (
57	              <StackItem key={n.iface.name}>{getPrintableNetworkInterfaceType(n.iface)}</StackItem>
58	            ))}
59	          </Stack>
60	        }
61	        title={t('Type')}
62	      />
63	    </DescriptionList>
64	  );
65	});
66	WizardOverviewNetworksTable.displayName = 'WizardOverviewNetworksTable';

